srgb_to_hsv_roundtrip_test_() ->
	[srgb_to_hsv_roundtrip_case(Etalon) || Etalon <- etalon_colors(), Etalon#color_etalon.hsv =/= undefined].

srgb_to_hsv_roundtrip_case(#color_etalon{name = Name, srgb = Srgb, hsv = ExpectedHsv}) ->
	fun() ->
		ConvertedHsv = cbet:convert(Srgb, #hsv{illum = ?ILLUM_D65}),
		BackSrgb = cbet:convert(ConvertedHsv, #srgb{}),

		H_diff = abs(normalize_hue_diff(ConvertedHsv#hsv.h - ExpectedHsv#hsv.h)),
		S_diff = abs(ConvertedHsv#hsv.s - ExpectedHsv#hsv.s),
		V_diff = abs(ConvertedHsv#hsv.v - ExpectedHsv#hsv.v),

		R_diff = abs(BackSrgb#srgb.r - Srgb#srgb.r),
		G_diff = abs(BackSrgb#srgb.g - Srgb#srgb.g),
		B_diff = abs(BackSrgb#srgb.b - Srgb#srgb.b),

		Tol = 0.001,
		TolHue = 0.1,
		TolRGB = Tol,

		case {H_diff < TolHue, S_diff < Tol, V_diff < Tol, R_diff < TolRGB, G_diff < TolRGB, B_diff < TolRGB} of
			{true, true, true, true, true, true} ->
				ok;
			_ ->
				io:format("~n=== Падение теста srgb_to_hsv_roundtrip на '~s' ===~n"
				"Вход sRGB:      ~p~n"
				"Ожидаемый HSV:  ~p~n"
				"Полученный HSV: ~p~n"
				"Разница H/S/V:  ~.4f / ~.6f / ~.6f~n"
				"Back sRGB:      ~p~n"
