%% ==================== Adobe RGB roundtrip ====================
srgb_to_adobe_rgb_roundtrip_test_() ->
	[srgb_to_adobe_rgb_roundtrip_case(Etalon) || Etalon <- etalon_colors(), Etalon#color_etalon.adobe_rgb =/= undefined].

srgb_to_adobe_rgb_roundtrip_case(#color_etalon{name = Name, srgb = Srgb, adobe_rgb = ExpectedAdobe}) ->
	fun() ->
		Converted = cbet:convert(Srgb, #adobe_rgb{illum = ?ILLUM_D65}),
		BackSrgb = cbet:convert(Converted, #srgb{}),

		R_diff = abs(Converted#adobe_rgb.r - ExpectedAdobe#adobe_rgb.r),
		G_diff = abs(Converted#adobe_rgb.g - ExpectedAdobe#adobe_rgb.g),
		B_diff = abs(Converted#adobe_rgb.b - ExpectedAdobe#adobe_rgb.b),

		BackR = abs(BackSrgb#srgb.r - Srgb#srgb.r),
		BackG = abs(BackSrgb#srgb.g - Srgb#srgb.g),
		BackB = abs(BackSrgb#srgb.b - Srgb#srgb.b),

		Tol = 0.002,   % чуть больше, чем для HSV/HSL, из-за матричных погрешностей

		case {R_diff < Tol, G_diff < Tol, B_diff < Tol, BackR < Tol, BackG < Tol, BackB < Tol} of
			{true, true, true, true, true, true} -> ok;
			_ ->
				io:format("~n=== FAIL srgb <-> adobe_rgb roundtrip '~s' ===~n"
				"sRGB:      ~p~n"
				"Expected Adobe: ~p~n"
				"Got Adobe:      ~p~n"
				"ΔR/G/B Adobe:   ~.6f / ~.6f / ~.6f~n"
				"Back sRGB:      ~p~n"
				"ΔR/G/B back:    ~.6f / ~.6f / ~.6f~n~n",
					[Name, Srgb, ExpectedAdobe, Converted, R_diff, G_diff, B_diff, BackSrgb, BackR, BackG, BackB]),
				?assert(false)
		end
	end.


%% ==================== Adobe RGB out of gamut for SRGB ====================
adobe_rgb_to_srgb_out_of_gamut_test_() ->
	[adobe_rgb_to_srgb_out_of_gamut_case(Etalon) || Etalon <- etalon_colors(), Etalon#color_etalon.adobe_rgb_out_of_gamut =/= undefined].

adobe_rgb_to_srgb_out_of_gamut_case(#color_etalon{name = Name, srgb = ExpectedSrgbNoClamp, adobe_rgb_out_of_gamut = Argb}) ->
	fun() ->
		ExpectedSrgbClamp = ExpectedSrgbNoClamp#srgb{
			r = max(ExpectedSrgbNoClamp#srgb.r, 0.0),
			g = max(ExpectedSrgbNoClamp#srgb.g, 0.0),
			b = max(ExpectedSrgbNoClamp#srgb.b, 0.0)
		},

		ConvertedClamp = cbet:convert(Argb, #srgb{illum = ?ILLUM_D65}, #{clamp => true}),
		ConvertedNoClamp = cbet:convert(Argb, #srgb{illum = ?ILLUM_D65}, #{clamp => false}),

		RNoClamp_diff = abs(ConvertedNoClamp#srgb.r - ExpectedSrgbNoClamp#srgb.r),
		GNoClamp_diff = abs(ConvertedNoClamp#srgb.g - ExpectedSrgbNoClamp#srgb.g),
		BNoClamp_diff = abs(ConvertedNoClamp#srgb.b - ExpectedSrgbNoClamp#srgb.b),

		RClamp_diff = abs(ConvertedClamp#srgb.r - ExpectedSrgbClamp#srgb.r),
		GClamp_diff = abs(ConvertedClamp#srgb.g - ExpectedSrgbClamp#srgb.g),
		BClamp_diff = abs(ConvertedClamp#srgb.b - ExpectedSrgbClamp#srgb.b),


		Tol = 0.02,

		case {RNoClamp_diff < Tol, GNoClamp_diff < Tol, BNoClamp_diff < Tol,
			RClamp_diff < Tol, GClamp_diff < Tol, BClamp_diff < Tol} of
			{true, true, true, true, true, true} -> ok;
			_ ->
				io:format("~n=== FAIL adobe_rgb -> srgb (out of gamut) '~s' ===~n"
				"ARGB:      ~p~n"
				"Expected SRGB (no clamp): ~p~n"
				"Got SRGB (no clamp):      ~p~n"
				"Expected SRGB (clamp): ~p~n"
				"Got SRGB (clamp):      ~p~n",
					[Name, Argb, ExpectedSrgbNoClamp, ConvertedNoClamp,
						ExpectedSrgbClamp, ConvertedClamp]),
				?assert(false)
		end
	end.


%% ==================== Display P3 roundtrip ====================
srgb_to_display_p3_roundtrip_test_() ->
	[srgb_to_display_p3_roundtrip_case(Etalon) || Etalon <- etalon_colors(), Etalon#color_etalon.display_p3 =/= undefined].

srgb_to_display_p3_roundtrip_case(#color_etalon{name = Name, srgb = Srgb, display_p3 = ExpectedP3}) ->
	fun() ->
		Converted = cbet:convert(Srgb, #display_p3{illum = ?ILLUM_D65}),
		BackSrgb = cbet:convert(Converted, #srgb{}),

		R_diff = abs(Converted#display_p3.r - ExpectedP3#display_p3.r),
		G_diff = abs(Converted#display_p3.g - ExpectedP3#display_p3.g),
		B_diff = abs(Converted#display_p3.b - ExpectedP3#display_p3.b),

		BackR = abs(BackSrgb#srgb.r - Srgb#srgb.r),
		BackG = abs(BackSrgb#srgb.g - Srgb#srgb.g),
		BackB = abs(BackSrgb#srgb.b - Srgb#srgb.b),

		Tol = 0.02,

		case {R_diff < Tol, G_diff < Tol, B_diff < Tol, BackR < Tol, BackG < Tol, BackB < Tol} of
			{true, true, true, true, true, true} -> ok;
			_ ->
				io:format("~n=== FAIL srgb <-> display_p3 roundtrip '~s' ===~n"
				"sRGB:      ~p~n"
				"Expected P3: ~p~n"
				"Got P3:      ~p~n"
				"ΔR/G/B P3:   ~.6f / ~.6f / ~.6f~n"
				"Back sRGB:   ~p~n"
				"ΔR/G/B back: ~.6f / ~.6f / ~.6f~n~n",
					[Name, Srgb, ExpectedP3, Converted, R_diff, G_diff, B_diff, BackSrgb, BackR, BackG, BackB]),
				?assert(false)
		end
	end.

%% ==================== Rec.2020 roundtrip ====================
srgb_to_rec2020_roundtrip_test_() ->
    [srgb_to_rec2020_roundtrip_case(Etalon) || Etalon <- etalon_colors(), Etalon#color_etalon.rec2020 =/= undefined].


srgb_to_rec2020_roundtrip_case(#color_etalon{name=Name, srgb=Srgb, rec2020=ExpectedRec2020}) ->
    fun() ->
        Converted = cbet:convert(Srgb, #rec2020{illum=?ILLUM_D65}),
        BackSrgb = cbet:convert(Converted, #srgb{}),

        R_diff = abs(Converted#rec2020.r - ExpectedRec2020#rec2020.r),
        G_diff = abs(Converted#rec2020.g - ExpectedRec2020#rec2020.g),
        B_diff = abs(Converted#rec2020.b - ExpectedRec2020#rec2020.b),

        BackR_diff = abs(BackSrgb#srgb.r - Srgb#srgb.r),
        BackG_diff = abs(BackSrgb#srgb.g - Srgb#srgb.g),
        BackB_diff = abs(BackSrgb#srgb.b - Srgb#srgb.b),

        TolConverted = 0.008,
        TolBack      = 0.004,

        case {R_diff     < TolConverted,
              G_diff     < TolConverted,
              B_diff     < TolConverted,
              BackR_diff < TolBack,
              BackG_diff < TolBack,
              BackB_diff < TolBack} of
            {true, true, true, true, true, true} ->
                ok;
            _ ->
                io:format(
                    "~n=== FAIL srgb <-> rec2020 roundtrip '~s' ===~n"
                    "Вход sRGB:        ~p~n"
                    "Ожидаемый Rec2020: ~p~n"
                    "Полученный Rec2020:~p~n"
                    "ΔR/G/B в Rec2020:  ~.6f / ~.6f / ~.6f  (допуск ~.4f)~n"
                    "Обратно sRGB:      ~p~n"
                    "ΔR/G/B обратно:    ~.6f / ~.6f / ~.6f  (допуск ~.4f)~n~n",
                    [Name, Srgb, ExpectedRec2020, Converted,
                     R_diff, G_diff, B_diff, TolConverted,
                     BackSrgb, BackR_diff, BackG_diff, BackB_diff, TolBack]
                ),
                ?assert(false)
        end
    end.

