%% ==================== HWB roundtrip ====================
srgb_to_hwb_roundtrip_test_() ->
    [srgb_to_hwb_roundtrip_case(Etalon) || Etalon <- etalon_colors(), Etalon#color_etalon.hwb =/= undefined].


srgb_to_hwb_roundtrip_case(#color_etalon{name=Name, srgb=Srgb, hwb=ExpectedHwb}) ->
    fun() ->
        ConvertedHwb = cbet:convert(Srgb, #hwb{illum=?ILLUM_D65}),
        BackSrgb = cbet:convert(ConvertedHwb, #srgb{}),

        H_diff = abs(normalize_hue_diff(ConvertedHwb#hwb.h - ExpectedHwb#hwb.h)),
        W_diff = abs(ConvertedHwb#hwb.w - ExpectedHwb#hwb.w),
        B_diff = abs(ConvertedHwb#hwb.b - ExpectedHwb#hwb.b),

        R_diff = abs(BackSrgb#srgb.r - Srgb#srgb.r),
        G_diff = abs(BackSrgb#srgb.g - Srgb#srgb.g),
        B_rgb_diff = abs(BackSrgb#srgb.b - Srgb#srgb.b),

        TolHue   = 0.2,
        TolWB    = 0.001,
        TolRGB   = 0.0005,

        case {H_diff  < TolHue,
              W_diff  < TolWB,
              B_diff  < TolWB,
              R_diff  < TolRGB,
              G_diff  < TolRGB,
              B_rgb_diff < TolRGB} of
            {true, true, true, true, true, true} ->
                ok;
            _ ->
                io:format(
                    "~n=== FAIL srgb <-> hwb roundtrip '~s' ===~n"
                    "Вход sRGB:        ~p~n"
                    "Ожидаемый HWB:    ~p~n"
                    "Полученный HWB:   ~p~n"
                    "ΔH / ΔW / ΔB:     ~.4f / ~.6f / ~.6f~n"
                    "Обратно sRGB:     ~p~n"
                    "ΔR / ΔG / ΔB:     ~.7f / ~.7f / ~.7f  (допуск ~.4f)~n~n",
                    [Name, Srgb, ExpectedHwb, ConvertedHwb,
                     H_diff, W_diff, B_diff,
                     BackSrgb, R_diff, G_diff, B_rgb_diff, TolRGB]
                ),
                ?assert(false)
        end
    end.

