srgb_to_ipt_roundtrip_test_() ->
    [srgb_to_ipt_roundtrip_case(Etalon) || Etalon <- etalon_colors(), Etalon#color_etalon.ipt =/= undefined].


srgb_to_ipt_roundtrip_case(#color_etalon{name=Name, srgb=Srgb, ipt=ExpectedIpt}) ->
    fun() ->
        ConvertedIpt = cbet:convert(Srgb, #ipt{illum=?ILLUM_D65}),
        BackSrgb = cbet:convert(ConvertedIpt, #srgb{}),

        I_diff = abs(ConvertedIpt#ipt.i - ExpectedIpt#ipt.i),
        P_diff = abs(ConvertedIpt#ipt.p - ExpectedIpt#ipt.p),
        T_diff = abs(ConvertedIpt#ipt.t - ExpectedIpt#ipt.t),

        R_diff = abs(BackSrgb#srgb.r - Srgb#srgb.r),
        G_diff = abs(BackSrgb#srgb.g - Srgb#srgb.g),
        B_diff = abs(BackSrgb#srgb.b - Srgb#srgb.b),

        TolIPT   = 0.008,     % типичный допуск для I/P/T (может быть 0.005–0.015)
        TolRGB   = 0.003,

        case {I_diff < TolIPT,
              P_diff < TolIPT,
              T_diff < TolIPT,
              R_diff < TolRGB,
              G_diff < TolRGB,
              B_diff < TolRGB} of
            {true, true, true, true, true, true} ->
                ok;
            _ ->
                io:format(
                    "~n=== FAIL srgb <-> ipt roundtrip '~s' ===~n"
                    "Вход sRGB:      ~p~n"
                    "Ожидаемый IPT:  ~p~n"
                    "Полученный IPT: ~p~n"
                    "ΔI / ΔP / ΔT:   ~.6f / ~.6f / ~.6f  (допуск ~.4f)~n"
                    "Обратно sRGB:   ~p~n"
                    "ΔR / ΔG / ΔB:   ~.6f / ~.6f / ~.6f  (допуск ~.4f)~n~n",
                    [Name, Srgb, ExpectedIpt, ConvertedIpt,
                     I_diff, P_diff, T_diff, TolIPT,
                     BackSrgb, R_diff, G_diff, B_diff, TolRGB]
                ),
                ?assert(false)
        end
    end.


%% ==================== CIE xyY roundtrip ====================
srgb_to_xyy_roundtrip_test_() ->
    [srgb_to_xyy_roundtrip_case(Etalon) || Etalon <- etalon_colors(), Etalon#color_etalon.xyy =/= undefined, Etalon#color_etalon.adobe_rgb_out_of_gamut == undefined].

adobe_rgb_out_of_gamut_to_xyy_roundtrip_test_() ->
    [adobe_rgb_out_of_gamut_to_xyy_roundtrip_case(Etalon) || Etalon <- etalon_colors(), Etalon#color_etalon.adobe_rgb_out_of_gamut =/= undefined, Etalon#color_etalon.xyy =/= undefined].


srgb_to_xyy_roundtrip_case(#color_etalon{name=Name, srgb=Srgb, xyy=ExpectedXyy}) ->
    fun() ->
        ConvertedXyy = cbet:convert(Srgb, #xyy{illum=?ILLUM_D65}),
        BackSrgb = cbet:convert(ConvertedXyy, #srgb{}),

        X_diff     = abs(ConvertedXyy#xyy.x         - ExpectedXyy#xyy.x),
        Y_diff     = abs(ConvertedXyy#xyy.y         - ExpectedXyy#xyy.y),
        Lum_diff   = abs(ConvertedXyy#xyy.luminance - ExpectedXyy#xyy.luminance),

        R_diff = abs(BackSrgb#srgb.r - Srgb#srgb.r),
        G_diff = abs(BackSrgb#srgb.g - Srgb#srgb.g),
        B_diff = abs(BackSrgb#srgb.b - Srgb#srgb.b),

        TolXY        = 0.002,
        TolLuminance = 0.7,


        TolRGB       = 0.001,

        case {X_diff     < TolXY,
              Y_diff     < TolXY,
              Lum_diff   < TolLuminance,
              R_diff     < TolRGB,
              G_diff     < TolRGB,
              B_diff     < TolRGB} of
            {true, true, true, true, true, true} ->
                ok;
            _ ->
                io:format(
                    "~n=== FAIL srgb <-> xyy roundtrip '~s' ===~n"
                    "Вход sRGB:         ~p~n"
                    "Ожидаемый xyY:     ~p~n"
                    "Полученный xyY:    ~p~n"
                    "Δx     = ~.6f~n"
                    "Δy     = ~.6f~n"
                    "ΔY/lum = ~.6f   (допуск ~.4f)~n"
                    "Обратно sRGB:      ~p~n"
                    "ΔR / ΔG / ΔB = ~.6f / ~.6f / ~.6f  (допуск ~.4f)~n~n",
                    [Name, Srgb, ExpectedXyy, ConvertedXyy,
                     X_diff, Y_diff, Lum_diff, TolLuminance,
                     BackSrgb, R_diff, G_diff, B_diff, TolRGB]
                ),
                ?assert(false)
        end
    end.


adobe_rgb_out_of_gamut_to_xyy_roundtrip_case(#color_etalon{name=Name, adobe_rgb_out_of_gamut = Argb, xyy=ExpectedXyy}) ->
    fun() ->
        ConvertedXyy = cbet:convert(Argb, #xyy{illum=?ILLUM_D65}),
        BackArgb = cbet:convert(ConvertedXyy, #adobe_rgb{}),

        X_diff     = abs(ConvertedXyy#xyy.x         - ExpectedXyy#xyy.x),
        Y_diff     = abs(ConvertedXyy#xyy.y         - ExpectedXyy#xyy.y),
        Lum_diff   = abs(ConvertedXyy#xyy.luminance - ExpectedXyy#xyy.luminance),

        R_diff = abs(BackArgb#adobe_rgb.r - Argb#adobe_rgb.r),
        G_diff = abs(BackArgb#adobe_rgb.g - Argb#adobe_rgb.g),
        B_diff = abs(BackArgb#adobe_rgb.b - Argb#adobe_rgb.b),

        TolXY        = 0.002,
        TolLuminance = 0.7,
        TolRGB       = 0.001,

        case {X_diff     < TolXY,
              Y_diff     < TolXY,
              Lum_diff   < TolLuminance,
              R_diff     < TolRGB,
              G_diff     < TolRGB,
              B_diff     < TolRGB} of
            {true, true, true, true, true, true} ->
                ok;
            _ ->
                io:format(
                    "~n=== FAIL argb out of gamut for srgb <-> xyy roundtrip '~s' ===~n"
                    "Вход aRGB:         ~p~n"
                    "Ожидаемый xyY:     ~p~n"
                    "Полученный xyY:    ~p~n"
                    "Δx     = ~.6f~n"
                    "Δy     = ~.6f~n"
                    "ΔY/lum = ~.6f   (допуск ~.4f)~n"
                    "Обратно aRGB:      ~p~n"
                    "ΔR / ΔG / ΔB = ~.6f / ~.6f / ~.6f  (допуск ~.4f)~n~n",
                    [Name, Argb, ExpectedXyy, ConvertedXyy,
                     X_diff, Y_diff, Lum_diff, TolLuminance,
                     BackArgb, R_diff, G_diff, B_diff, TolRGB]
                ),
                ?assert(false)
        end
    end.


