                    "Δv           = ~.6f~n"
                    "Обратно sRGB:        ~p~n"
                    "ΔR / ΔG / ΔB = ~.6f / ~.6f / ~.6f  (допуск ~.4f)~n~n",
                    [Name, Srgb, ExpectedLogLuv, ConvertedLogLuv,
                     L_diff, U_diff, V_diff,
                     BackSrgb, R_diff, G_diff, B_diff, TolRGB]
                ),
                ?assert(false)
        end
    end.

%% ==================== DIN99d Lab roundtrip ====================
srgb_to_din99d_lab_roundtrip_test_() ->
    [srgb_to_din99d_lab_roundtrip_case(Etalon) || Etalon <- etalon_colors(), Etalon#color_etalon.din99d_lab =/= undefined].


srgb_to_din99d_lab_roundtrip_case(#color_etalon{name=Name, srgb=Srgb, din99d_lab=ExpectedDin99d}) ->
    fun() ->
        % Важно: передаём variant явно, чтобы гарантировать DIN99d
        ConvertedDin99d = cbet:convert(Srgb, #din99_lab{illum=?ILLUM_D50, variant=?DIN99d}),
        BackSrgb = cbet:convert(ConvertedDin99d, #srgb{}),

        L_diff = abs(ConvertedDin99d#din99_lab.l - ExpectedDin99d#din99_lab.l),
        A_diff = abs(ConvertedDin99d#din99_lab.a - ExpectedDin99d#din99_lab.a),
        B_diff = abs(ConvertedDin99d#din99_lab.b - ExpectedDin99d#din99_lab.b),

        R_diff = abs(BackSrgb#srgb.r - Srgb#srgb.r),
        G_diff = abs(BackSrgb#srgb.g - Srgb#srgb.g),
        B_rgb_diff = abs(BackSrgb#srgb.b - Srgb#srgb.b),


        TolL   = 0.20,
        TolAB  = 1.00,
        TolRGB = 0.005,

        case {L_diff   < TolL,
              A_diff   < TolAB,
              B_diff   < TolAB,
              R_diff   < TolRGB,
              G_diff   < TolRGB,
              B_rgb_diff < TolRGB} of
            {true, true, true, true, true, true} ->
                ok;
            _ ->
                io:format(
                    "~n=== FAIL srgb <-> din99d_lab roundtrip '~s' ===~n"
                    "Вход sRGB:           ~p~n"
                    "Ожидаемый DIN99d Lab:~p~n"
                    "Полученный DIN99d Lab:~p~n"
                    "ΔL     = ~.4f~n"
                    "Δa     = ~.4f~n"
                    "Δb     = ~.4f~n"
                    "Обратно sRGB:         ~p~n"
                    "ΔR / ΔG / ΔB = ~.6f / ~.6f / ~.6f  (допуск ~.4f)~n~n",
                    [Name, Srgb, ExpectedDin99d, ConvertedDin99d,
                     L_diff, A_diff, B_diff,
                     BackSrgb, R_diff, G_diff, B_rgb_diff, TolRGB]
                ),
                ?assert(false)
        end
    end.

%% ==================== LCH roundtrip ====================
srgb_to_lch_roundtrip_test_() ->
    [srgb_to_lch_roundtrip_case(Etalon) || Etalon <- etalon_colors(), Etalon#color_etalon.lch =/= undefined].


srgb_to_lch_roundtrip_case(#color_etalon{name=Name, srgb=Srgb, lch=ExpectedLch}) ->
    fun() ->
        ConvertedLch = cbet:convert(Srgb, #lch{illum=?ILLUM_D65}),
        BackSrgb = cbet:convert(ConvertedLch, #srgb{}),

        H_diff = abs(normalize_hue_diff(ConvertedLch#lch.h - ExpectedLch#lch.h)),
        C_diff = abs(ConvertedLch#lch.c - ExpectedLch#lch.c),
        L_diff = abs(ConvertedLch#lch.l - ExpectedLch#lch.l),

        R_diff = abs(BackSrgb#srgb.r - Srgb#srgb.r),
        G_diff = abs(BackSrgb#srgb.g - Srgb#srgb.g),
        B_diff = abs(BackSrgb#srgb.b - Srgb#srgb.b),


        TolHue   = 0.5,
        TolC     = 0.8,
        TolL     = 0.15,
        TolRGB   = 0.004,

        case {H_diff < TolHue,
              C_diff < TolC,
              L_diff < TolL,
              R_diff < TolRGB,
              G_diff < TolRGB,
              B_diff < TolRGB} of
            {true, true, true, true, true, true} ->
                ok;
            _ ->
                io:format(
                    "~n=== FAIL srgb <-> lch roundtrip '~s' ===~n"
                    "Вход sRGB:       ~p~n"
                    "Ожидаемый LCH:   ~p~n"
                    "Полученный LCH:  ~p~n"
                    "ΔH (hue) = ~.4f~n"
                    "ΔC (chroma) = ~.4f~n"
                    "ΔL (lightness) = ~.4f~n"
                    "Обратно sRGB:    ~p~n"
                    "ΔR / ΔG / ΔB = ~.6f / ~.6f / ~.6f  (допуск ~.4f)~n~n",
                    [Name, Srgb, ExpectedLch, ConvertedLch,
                     H_diff, C_diff, L_diff,
                     BackSrgb, R_diff, G_diff, B_diff, TolRGB]
                ),
                ?assert(false)
        end
    end.


%% ==================== Oklab roundtrip ====================
srgb_to_oklab_roundtrip_test_() ->
    [srgb_to_oklab_roundtrip_case(Etalon) || Etalon <- etalon_colors(), Etalon#color_etalon.oklab =/= undefined].


srgb_to_oklab_roundtrip_case(#color_etalon{name=Name, srgb=Srgb, oklab=ExpectedOklab}) ->
    fun() ->
        ConvertedOklab = cbet:convert(Srgb, #oklab{}),
        BackSrgb = cbet:convert(ConvertedOklab, #srgb{}),

        L_diff = abs(ConvertedOklab#oklab.l - ExpectedOklab#oklab.l),
        A_diff = abs(ConvertedOklab#oklab.a - ExpectedOklab#oklab.a),
        B_diff = abs(ConvertedOklab#oklab.b - ExpectedOklab#oklab.b),

        R_diff = abs(BackSrgb#srgb.r - Srgb#srgb.r),
        G_diff = abs(BackSrgb#srgb.g - Srgb#srgb.g),
        B_rgb_diff = abs(BackSrgb#srgb.b - Srgb#srgb.b),

        % Oklab — очень равномерное пространство
        % round-trip обычно точный, но на очень насыщенных цветах может быть небольшая погрешность
        TolL   = 0.004,     % Lightness — очень точная
        TolAB  = 0.008,     % a и b — обычно лучше, чем в CIELAB
        TolRGB = 0.002,     % обратный round-trip в sRGB

        case {L_diff   < TolL,
              A_diff   < TolAB,
              B_diff   < TolAB,
              R_diff   < TolRGB,
              G_diff   < TolRGB,
              B_rgb_diff < TolRGB} of
            {true, true, true, true, true, true} ->
                ok;
            _ ->
                io:format(
                    "~n=== FAIL srgb <-> oklab roundtrip '~s' ===~n"
                    "Вход sRGB:       ~p~n"
                    "Ожидаемый Oklab: ~p~n"
                    "Полученный Oklab:~p~n"
                    "ΔL = ~.6f~n"
                    "Δa = ~.6f~n"
                    "Δb = ~.6f~n"
                    "Обратно sRGB:    ~p~n"
                    "ΔR / ΔG / ΔB = ~.6f / ~.6f / ~.6f  (допуск ~.4f)~n~n",
                    [Name, Srgb, ExpectedOklab, ConvertedOklab,
                     L_diff, A_diff, B_diff,
                     BackSrgb, R_diff, G_diff, B_rgb_diff, TolRGB]
                ),
                ?assert(false)
        end
    end.


%% ==================== Oklch roundtrip ====================
srgb_to_oklch_roundtrip_test_() ->
    [srgb_to_oklch_roundtrip_case(Etalon) || Etalon <- etalon_colors(), Etalon#color_etalon.oklch =/= undefined].


srgb_to_oklch_roundtrip_case(#color_etalon{name=Name, srgb=Srgb, oklch=ExpectedOklch}) ->
    fun() ->
        ConvertedOklch = cbet:convert(Srgb, #oklch{}),
        BackSrgb = cbet:convert(ConvertedOklch, #srgb{}),

        L_diff = abs(ConvertedOklch#oklch.l - ExpectedOklch#oklch.l),
        C_diff = abs(ConvertedOklch#oklch.c - ExpectedOklch#oklch.c),
        H_diff = abs(normalize_hue_diff(ConvertedOklch#oklch.h - ExpectedOklch#oklch.h)),

        R_diff = abs(BackSrgb#srgb.r - Srgb#srgb.r),
        G_diff = abs(BackSrgb#srgb.g - Srgb#srgb.g),
        B_diff = abs(BackSrgb#srgb.b - Srgb#srgb.b),

        TolL   = 0.004,     % Lightness — очень точная
        TolC   = 0.012,     % Chroma — чуть больше погрешность, чем в Oklab a/b
        TolHue = 0.4,       % Hue — циклический, небольшая погрешность на границах
        TolRGB = 0.0025,    % обратный round-trip

        case {L_diff < TolL,
              C_diff < TolC,
              H_diff < TolHue,
              R_diff < TolRGB,
              G_diff < TolRGB,
              B_diff < TolRGB} of
            {true, true, true, true, true, true} ->
                ok;
            _ ->
                io:format(
                    "~n=== FAIL srgb <-> oklch roundtrip '~s' ===~n"
                    "Вход sRGB:        ~p~n"
                    "Ожидаемый Oklch:  ~p~n"
                    "Полученный Oklch: ~p~n"
                    "ΔL = ~.6f~n"
                    "ΔC = ~.6f~n"
                    "ΔH = ~.4f  (hue diff после нормализации)~n"
                    "Обратно sRGB:     ~p~n"
                    "ΔR / ΔG / ΔB = ~.6f / ~.6f / ~.6f  (допуск ~.4f)~n~n",
                    [Name, Srgb, ExpectedOklch, ConvertedOklch,
                     L_diff, C_diff, H_diff,
                     BackSrgb, R_diff, G_diff, B_diff, TolRGB]
                ),
                ?assert(false)
        end
    end.


