        case {I_diff  < TolI,
              Ct_diff < TolCtCp,
              Cp_diff < TolCtCp,
              R_diff  < TolRGB,
              G_diff  < TolRGB,
              B_diff  < TolRGB} of
            {true, true, true, true, true, true} ->
                ok;
            _ ->
                io:format(
                    "~n=== FAIL srgb <-> ictcp_pq roundtrip '~s' ===~n"
                    "Вход sRGB:           ~p~n"
                    "Ожидаемый ICtCp PQ:  ~p~n"
                    "Полученный ICtCp:    ~p~n"
                    "ΔI     = ~.6f~n"
                    "ΔCt    = ~.6f~n"
                    "ΔCp    = ~.6f~n"
                    "Обратно sRGB:        ~p~n"
                    "ΔR / ΔG / ΔB = ~.6f / ~.6f / ~.6f  (допуск ~.4f)~n~n",
                    [Name, Srgb, ExpectedIctcp, ConvertedIctcp,
                     I_diff, Ct_diff, Cp_diff,
                     BackSrgb, R_diff, G_diff, B_diff, TolRGB]
                ),
                ?assert(false)
        end
