cam16_test() ->
	ExpectedResult = #cam16{j = 41.731, c = 0.1033557,
		h_angle = 217.067959, h_quad = 275.594986,
		m = 0.10743677, s = 2.345015,
		q = 195.3717, a = 23.93954594544513,
		b = -4.790725135415859e-4, d = 0.9944687800884374, f = 1.0,
		c_sur = 0.69, n_c = 1.0},

	Result = cbet:cam16_model({19.01, 20.00, 21.78}, {95.05, 100.00, 108.88}, 318.31, 20.0, #{surround => average, compute_H => true}),
	LR = tuple_to_list(Result),
	LEx = tuple_to_list(ExpectedResult),
	[
		?assert(abs(A - B) < min(abs(A), abs(B)) / 1000.0)
		|| {A, B} <- tl(lists:zip(LR, LEx))
	].


nayatani_test() ->
	ExpectedResult = #nayatani{lstar_p = 49.99988,
		lstar_n = 50.003915, c = 0.013355,
		h_angle = 257.5232, s = 0.013355,
		q = 62.62667, m = 0.016726,
		h_q = 288.17419,
		h_c_segment = g_b,
		h_c = 0.8188},

	Result = cbet:nayatani_model({19.01, 20.00, 21.78}, {95.05, 100.00, 108.88}, 20.0, 5000.0, 1000.0),
	LR = tuple_to_list(Result),
	LEx = tuple_to_list(ExpectedResult),
	[
		?assert(abs(A - B) < min(abs(A), abs(B)) / 1000.0)
		|| {A, B} <- tl(lists:zip(LR, LEx)), not is_atom(A)
	],
	?assertEqual(Result#nayatani.h_c_segment, ExpectedResult#nayatani.h_c_segment).


hunt_test() ->
