%% ===================================================================
%% Вспомогательная функция для нормализации разницы hue (учитывает 360° цикл)
%% ===================================================================
normalize_hue_diff(Diff) ->
	abs(math:fmod(Diff + 180.0, 360.0) - 180.0).

